import {localStorageAdapter} from "../storage/localStorageAdapter.js";
import {getCourseById,getEnrollmentsByCourseId,getAccountById,getAccounts,addSecurityAuditLog,createNotification} from "../mockDatabase.js";
import {trainingApiService} from "./trainingApiService.js";
const SESSIONS="mykis.offlineSessions.v1",REGISTRATIONS="mykis.sessionRegistrations.v1",PARTICIPANTS="mykis.sessionParticipants.v1",REVISION="mykis.trainingDataRevision.v1";
const now=()=>new Date().toISOString();
const bump=()=>localStorageAdapter.write(REVISION,Number(localStorageAdapter.read(REVISION,0))+1);

// Fire-and-forget API sync helpers — never block the synchronous service
function apiSyncSession(session, actorAccountId) {
  trainingApiService.saveSession(session, actorAccountId).catch(() => {});
}
function apiSyncParticipants(sessionId, participants, actorAccountId) {
  trainingApiService.syncParticipants(sessionId, participants, actorAccountId).catch((error) => {
    console.error("Participant sync failed", { sessionId, message: error?.message || String(error) });
  });
}
function apiSyncRegistrations(registrations, actorAccountId) {
  trainingApiService.syncRegistrations(registrations, actorAccountId, "hr").catch(() => {});
}
const employeeAccounts=()=>getAccounts().filter(account=>account.role==="employee"&&account.accountStatus==="active");
const uniqueIds=(values=[])=>[...new Set(values.filter(Boolean))];
export const offlineTrainingService={
  getRevision(){return Number(localStorageAdapter.read(REVISION,0));},
  listSessions({courseId="",status=""}={}){return localStorageAdapter.read(SESSIONS,[]).filter(x=>(!courseId||x.courseId===courseId)&&(!status||x.status===status)).sort((a,b)=>a.startAt.localeCompare(b.startAt));},
  getSession(id){return this.listSessions().find(x=>x.id===id)||null;},
  saveSession(data,actorAccountId){if(getAccountById(actorAccountId)?.role!=="hr")return {ok:false,error:"forbidden"};const start=new Date(data.startAt),end=new Date(data.endAt),deadline=data.registrationDeadline?new Date(data.registrationDeadline):null;if(!data.courseId||!String(data.title||"").trim()||!Number.isFinite(+start)||!Number.isFinite(+end)||end<=start)return {ok:false,error:"invalid_time"};if(data.locationType==="onsite"&&!String(data.locationName||"").trim())return {ok:false,error:"location_required"};if(deadline&&deadline>=start)return {ok:false,error:"invalid_deadline"};const rows=localStorageAdapter.read(SESSIONS,[]),index=rows.findIndex(x=>x.id===data.id);const prior=index>=0?rows[index]:null;const row={id:prior?.id||crypto.randomUUID(),courseId:data.courseId,title:String(data.title).trim(),description:String(data.description||""),trainerName:String(data.trainerName||""),trainerType:data.trainerType||"internal",startAt:start.toISOString(),endAt:end.toISOString(),timezone:"Asia/Ho_Chi_Minh",locationType:data.locationType||"onsite",locationName:String(data.locationName||""),address:String(data.address||""),meetingUrl:String(data.meetingUrl||""),capacity:Math.max(1,Math.floor(Number(data.capacity)||1)),registrationDeadline:deadline?.toISOString()||"",attendanceRequired:data.attendanceRequired!==false,status:data.status||"scheduled",attendanceLocked:prior?.attendanceLocked||false,createdBy:prior?.createdBy||actorAccountId,createdAt:prior?.createdAt||now(),updatedAt:now()};if(index>=0)rows[index]=row;else rows.push(row);localStorageAdapter.write(SESSIONS,rows);bump();addSecurityAuditLog({action:prior?"Update offline session":"Create offline session",targetAccountId:row.id,targetEmployeeName:getCourseById(row.courseId)?.title||row.courseId,description:row.title});apiSyncSession(row,actorAccountId);return {ok:true,session:row};},
  listParticipants(sessionId=""){return localStorageAdapter.read(PARTICIPANTS,[]).filter(row=>!sessionId||row.sessionId===sessionId).sort((a,b)=>String(a.addedAt).localeCompare(String(b.addedAt)));},
  getParticipantAccountIds(sessionId){return uniqueIds(this.listParticipants(sessionId).map(row=>row.accountId));},
  setParticipants(sessionId,accountIds,actorAccountId,{mode="merge",source="manual"}={}){if(getAccountById(actorAccountId)?.role!=="hr")return {ok:false,error:"forbidden"};const session=this.getSession(sessionId);if(!session)return {ok:false,error:"not_found"};const valid=new Set(employeeAccounts().map(account=>account.id));const nextIds=uniqueIds(accountIds).filter(accountId=>valid.has(accountId));const rows=localStorageAdapter.read(PARTICIPANTS,[]);const preserved=mode==="replace"?rows.filter(row=>row.sessionId!==sessionId):rows.slice();const existingIds=new Set(preserved.filter(row=>row.sessionId===sessionId).map(row=>row.accountId));nextIds.forEach(accountId=>{if(existingIds.has(accountId))return;preserved.push({id:crypto.randomUUID(),sessionId,accountId,source,addedAt:now(),addedBy:actorAccountId});});localStorageAdapter.write(PARTICIPANTS,preserved);this.ensureInvitations(sessionId);bump();const finalParticipants=this.listParticipants(sessionId);apiSyncParticipants(sessionId,finalParticipants,actorAccountId);return {ok:true,participants:finalParticipants};},
  async setParticipantsAsync(sessionId,accountIds,actorAccountId,{mode="merge",source="manual"}={}){const actorAccount=getAccountById(actorAccountId);if(actorAccount&&actorAccount.role!=="hr")return {ok:false,error:"forbidden"};const session=this.getSession(sessionId);if(!session)return {ok:false,error:"not_found"};const allKnownIds=new Set(getAccounts().map(account=>account.id));const nextIds=uniqueIds(accountIds).filter(accountId=>allKnownIds.size===0||allKnownIds.has(accountId));const currentRows=localStorageAdapter.read(PARTICIPANTS,[]);const preserved=mode==="replace"?currentRows.filter(row=>row.sessionId!==sessionId):currentRows.slice();const existingByAccount=new Map(preserved.filter(row=>row.sessionId===sessionId).map(row=>[row.accountId,row]));nextIds.forEach(accountId=>{if(existingByAccount.has(accountId))return;const row={id:crypto.randomUUID(),sessionId,accountId,role:"learner",status:"assigned",source,createdAt:now(),addedAt:now(),addedBy:actorAccountId};preserved.push(row);existingByAccount.set(accountId,row);});const finalParticipants=preserved.filter(row=>row.sessionId===sessionId);try{const response=await trainingApiService.syncParticipants(sessionId,finalParticipants,actorAccountId,{mode});if(!response?.ok)throw new Error(response?.error||"participant_sync_failed");localStorageAdapter.write(PARTICIPANTS,preserved);this.ensureInvitations(sessionId);bump();addSecurityAuditLog({action:"Sync training participants",targetAccountId:sessionId,targetEmployeeName:session.title,description:`${finalParticipants.length} participant(s) synced to shared storage.`});return {ok:true,participants:finalParticipants,remoteCount:response.count};}catch(error){console.error("Unable to save training participants",{sessionId,message:error?.message||String(error)});return {ok:false,error:"remote_sync_failed",message:error?.message||"Không thể lưu học viên vào Supabase."};}},
  addParticipantsByCourseAssignments(sessionId,actorAccountId){const session=this.getSession(sessionId);if(!session)return {ok:false,error:"not_found"};return this.setParticipants(sessionId,getEnrollmentsByCourseId(session.courseId).map(row=>row.accountId),actorAccountId,{mode:"merge",source:"course_assignment"});},
  addParticipantsByDepartments(sessionId,departments,actorAccountId){const departmentSet=new Set(uniqueIds(departments));const ids=employeeAccounts().filter(account=>departmentSet.has(account.department)).map(account=>account.id);return this.setParticipants(sessionId,ids,actorAccountId,{mode:"merge",source:"department"});},
  removeParticipant(sessionId,accountId,actorAccountId){if(getAccountById(actorAccountId)?.role!=="hr")return false;const rows=localStorageAdapter.read(PARTICIPANTS,[]);const next=rows.filter(row=>!(row.sessionId===sessionId&&row.accountId===accountId));if(next.length===rows.length)return false;localStorageAdapter.write(PARTICIPANTS,next);bump();trainingApiService.removeParticipant(sessionId,accountId,actorAccountId).catch(()=>{});return true;},
  participantSummary(sessionId){const session=this.getSession(sessionId);if(!session)return {selected:0,capacity:0,remaining:0,overBy:0};const selected=this.getParticipantAccountIds(sessionId).length,capacity=Math.max(0,Number(session.capacity)||0),remaining=Math.max(0,capacity-selected),overBy=Math.max(0,selected-capacity);return {selected,capacity,remaining,overBy};},
  registrations(sessionId=""){return localStorageAdapter.read(REGISTRATIONS,[]).filter(x=>!sessionId||x.sessionId===sessionId);},
  getRegistration(sessionId,accountId){return this.registrations(sessionId).find(x=>x.accountId===accountId)||null;},
  ensureInvitations(sessionId){const session=this.getSession(sessionId);if(!session)return [];const rows=localStorageAdapter.read(REGISTRATIONS,[]);const allowedIds=new Set(this.getParticipantAccountIds(sessionId));for(const accountId of allowedIds){if(!rows.some(x=>x.sessionId===sessionId&&x.accountId===accountId))rows.push({id:crypto.randomUUID(),sessionId,accountId,responseStatus:"pending",responseReason:"",respondedAt:"",attendanceStatus:"not_marked",checkInAt:"",checkOutAt:"",attendedSeconds:0,attendanceNote:"",markedBy:"",markedAt:"",createdAt:now(),updatedAt:now()});}localStorageAdapter.write(REGISTRATIONS,rows);const freshRegs=rows.filter(x=>x.sessionId===sessionId&&allowedIds.has(x.accountId));apiSyncRegistrations(freshRegs,"system");return freshRegs;},
  respond(sessionId,accountId,responseStatus,responseReason=""){const session=this.getSession(sessionId);if(!session||session.status!=="scheduled"||!["attending","busy","declined"].includes(responseStatus))return {ok:false,error:"invalid_response"};if(session.registrationDeadline&&new Date()>new Date(session.registrationDeadline))return {ok:false,error:"deadline_passed"};this.ensureInvitations(sessionId);const rows=localStorageAdapter.read(REGISTRATIONS,[]),index=rows.findIndex(x=>x.sessionId===sessionId&&x.accountId===accountId);if(index<0)return {ok:false,error:"not_invited"};rows[index]={...rows[index],responseStatus,responseReason:String(responseReason||""),respondedAt:now(),updatedAt:now()};localStorageAdapter.write(REGISTRATIONS,rows);bump();createNotification({type:"offline_response",targetAccountId:accountId,title:responseStatus==="attending"?"Đã xác nhận tham gia":"Đã ghi nhận báo bận",body:session.title,actionUrl:`/dashboard/calendar?sessionId=${sessionId}`});const updatedReg=rows[index];trainingApiService.patchRegistration(sessionId,accountId,updatedReg,accountId,"employee").catch(()=>{});return {ok:true,registration:updatedReg};},
  markAttendance(sessionId,accountId,data,actorAccountId){const session=this.getSession(sessionId);if(!session||getAccountById(actorAccountId)?.role!=="hr")return {ok:false,error:"forbidden"};if(session.attendanceLocked)return {ok:false,error:"attendance_locked"};this.ensureInvitations(sessionId);const rows=localStorageAdapter.read(REGISTRATIONS,[]),index=rows.findIndex(x=>x.sessionId===sessionId&&x.accountId===accountId);if(index<0)return {ok:false,error:"not_found"};const status=data.attendanceStatus;if(!["not_marked","attended","partial","absent","excused"].includes(status))return {ok:false,error:"invalid_status"};const scheduled=Math.max(0,(new Date(session.endAt)-new Date(session.startAt))/1000);let seconds=0;if(status==="attended"||status==="partial"){const checkIn=data.checkInAt?new Date(data.checkInAt):null,checkOut=data.checkOutAt?new Date(data.checkOutAt):null;if(checkIn&&checkOut&&checkOut>checkIn)seconds=Math.min(scheduled,(checkOut-checkIn)/1000);else seconds=Math.min(scheduled,Math.max(0,Number(data.attendedMinutes??(status==="attended"?scheduled/60:0))*60));}rows[index]={...rows[index],attendanceStatus:status,checkInAt:data.checkInAt||"",checkOutAt:data.checkOutAt||"",attendedSeconds:Math.round(seconds),attendanceNote:String(data.attendanceNote||""),markedBy:actorAccountId,markedAt:now(),updatedAt:now()};localStorageAdapter.write(REGISTRATIONS,rows);bump();addSecurityAuditLog({action:"Mark attendance",targetAccountId:accountId,targetEmployeeName:getAccountById(accountId)?.fullName||accountId,description:`${session.title}: ${status}, ${Math.round(seconds/60)} minutes`});const markedReg=rows[index];trainingApiService.patchRegistration(session.id,accountId,markedReg,actorAccountId,"hr").catch(()=>{});return {ok:true,registration:markedReg};},
  setAttendanceLocked(sessionId,locked,actorAccountId,reason=""){if(getAccountById(actorAccountId)?.role!=="hr")return false;const rows=localStorageAdapter.read(SESSIONS,[]);const index=rows.findIndex(row=>row.id===sessionId);if(index<0)return false;rows[index]={...rows[index],attendanceLocked:!!locked,attendanceLockReason:String(reason||""),attendanceLockedAt:locked?now():"",updatedAt:now()};localStorageAdapter.write(SESSIONS,rows);bump();return true;},
};
